INSERT INTO players (id, name, title, era, era_class, birth_year, bio, manuals)
VALUES
  (1, '朱晋桢', '象棋理论家', '明代·嘉靖年间', 'ming',    '约 1520—1570', '朱晋桢，明代著名象棋理论家，其所著《橘中秘》是中国象棋史上最重要的古谱之一。书中系统整理了炮局理论，对后世影响深远。', '[{"id":1,"title":"橘中秘·出车取士局"}]'),
  (2, '张乔栋', '屏风马宗师', '清代·乾隆年间', 'qing',    '约 1720—1790', '张乔栋，清代乾隆年间著名象棋家，以屏风马布局理论著称。其编撰的《梅花谱》系统论述了屏风马的各种变化，奠定了防御性布局的理论基础。', '[{"id":2,"title":"梅花谱·蚯蚓降龙"}]'),
  (3, '颜丙',   '开局理论家', '明代·成化年间', 'ming',    '约 1460—1530', '颜丙，明代成化年间象棋理论家，精研开局理论，尤以当头炮系列的研究最为深入，对明代象棋理论的发展做出了重要贡献。',               '[{"id":3,"title":"适情雅趣·当头炮进三兵"}]'),
  (4, '张志',   '残局大师',   '清代·道光年间', 'qing',    '约 1790—1860', '张志，清代道光年间著名棋手，以残局研究著称。其整理的残局精选汇集了历代名家残局，是训练象棋计算能力的重要教材。',                 '[{"id":4,"title":"韬略元机·顺炮横车对直车"}]'),
  (5, '晁补之', '文学家·棋手', '宋代',          'ancient', '1053—1110',    '晁补之，北宋著名文学家，苏门四学士之一，同时也是象棋爱好者。相传《百局象棋谱》为其所编，是现存最早的象棋谱之一。',               '[]'),
  (6, '谢侠逊', '象棋大师',   '近现代',         'modern',  '1888—1987',    '谢侠逊，近现代著名象棋家，有"象棋圣手"之称。毕生致力于象棋理论研究与推广，著有多部棋谱。',                                         '[]'),
  (7, '王天一', '特级大师',   '近现代',         'modern',  '1994 年生',    '王天一，现役象棋特级大师，多次荣获全国象棋个人锦标赛冠军。以深厚的理论功底和精湛的计算能力著称，是当代象棋界的领军人物。',           '[]'),
  (8, '谢靖',   '特级大师',   '近现代',         'modern',  '1991 年生',    '谢靖，象棋特级大师，多次荣获全国象棋冠军。棋风凌厉，善于攻杀，尤擅中局混战，在现役棋手中以计算精确、战术丰富著称。',               '[]')
INSERT INTO news (id, category, title, summary, source, date, content)
VALUES
  (1,  '赛事', '第四十届全国象棋个人锦标赛落幕 王天一成功卫冕冠军',       '经过14天激烈角逐，第四十届全国象棋个人锦标赛在广州圆满落幕。卫冕冠军王天一以11胜2平1负的成绩夺得冠军，谢靖、郑惟桐分列二三位。', '中国象棋协会', '2024-07-30', '<p>经过14天激烈角逐，第四十届全国象棋个人锦标赛在广州圆满落幕。</p><p>卫冕冠军王天一以11胜2平1负的成绩夺得冠军，谢靖、郑惟桐分列二三位。</p>'),
  (2,  '赛事', '象棋甲级联赛2024赛季总决赛：广东恒大VS浙江波尔',           '象棋甲级联赛2024赛季总决赛将于11月15日在杭州拉开帷幕，广东恒大队与浙江波尔队强强对决，争夺本赛季总冠军。',               '象棋联赛官网', '2024-11-10', NULL),
  (3,  '棋手', '许银川专访：象棋是一门艺术，需要用一生去追求',             '近日，象棋特级大师许银川接受本报专访，谈及从艺近四十年的心路历程。他表示，象棋不仅是竞技运动，更是中华文化的精髓体现。',     '体育周报',   '2024-11-05', NULL),
  (4,  '文化', '《橘中秘》成书500周年纪念活动在苏州举办',                 '明代象棋名著《橘中秘》成书500周年纪念活动近日在苏州隆重举办，活动包括古谱展览、学术研讨、名家表演赛等多个环节。',           '文化中国',   '2024-10-28', NULL),
  (5,  '技术', '人工智能助力象棋训练：AI引擎让古谱分析更精准',             '近年来，AI技术在象棋领域的应用日趋成熟。多款专业象棋AI引擎已能对古典棋谱进行深度分析，找出最优变化。',                   '科技象棋',   '2024-10-20', NULL),
  (6,  '赛事', '2024年亚洲象棋锦标赛：中国队包揽金牌',                     '2024年亚洲象棋锦标赛在马来西亚吉隆坡落幕，中国队在男女个人及团体四个项目上全部夺金，展现了绝对统治力。',                   '亚洲象棋联合会', '2024-10-15', NULL),
  (7,  '棋手', '90后棋手崛起：中国象棋进入新旧更迭关键期',                 '随着王天一、谢靖、郑惟桐等90后棋手逐渐成为主力，中国象棋正在经历新旧更迭的重要时期。',                                   '棋界观察',   '2024-10-08', NULL),
  (8,  '文化', '象棋进校园：全国已有超过两千所中小学开展象棋课',           '据中国象棋协会统计，截至2024年，全国已有超过2000所中小学将象棋纳入校本课程，参与学生人数突破50万。',                   '中国教育报', '2024-09-25', NULL),
  (9,  '技术', '残局研究新突破：计算机证明马炮胜单车的最短步数',           '中国象棋研究院利用高性能计算机对"马炮胜单车"残局进行了穷举计算，确定了最短取胜步数，为残局理论提供了重要数据。',           '象棋研究',   '2024-09-18', NULL),
  (10, '赛事', '第十四届全运会象棋项目：陕西赛区完赛',                     '第十四届全国运动会象棋项目在陕西西安圆满收官，共产生男子、女子、团体三项冠军，为全运会增添了浓厚的文化色彩。',             '全运会官网', '2024-09-10', NULL)
